mapper.select:
SELECT a.our_company_name, DATE_FORMAT( a.invoice_date, '%Y-%m' ) "invoiceDate", sum( a.deal_amount ) "invoiceAmount", sum(ROUND( a.deal_amount / b.total_amount * b.total_number, 2 )) "invoiceNumber" FROM t_apply_invoice a INNER JOIN t_ctr_contract b ON b.contract_no = a.contract_no
a.STATUS = 'D' AND b.status != 'C'
AND DATE_FORMAT( a.invoice_date, '%Y-%m' ) =#{invoiceDate}
AND a.our_company_name in
#{ourCompanyNameList[${index}],jdbcType=VARCHAR}
GROUP BY a.our_company_name, invoiceDate ORDER BY invoiceDate DESC

SELECT a.company_name "ourCompanyName", DATE_FORMAT( a.invoice_date, '%Y-%m' ) "invoiceDate", sum( a.deal_amount ) "invoiceReceiveAmount", sum(ROUND( a.deal_amount / b.total_amount * b.total_number, 2 )) "invoiceReceiveNumber" FROM t_apply_invoice a INNER JOIN t_ctr_dcsx b ON b.contract_no = a.contract_no
a.STATUS = 'D' AND b.status != 'C'
AND DATE_FORMAT( a.invoice_date, '%Y-%m' ) =#{invoiceDate}
AND a.company_name in
#{ourCompanyNameList[${index}],jdbcType=VARCHAR}
GROUP BY a.company_name, invoiceDate ORDER BY invoiceDate DESC
